chunks.content:
irtual_tokens = (virtual_tokens as u128)
        .checked_add(token_in as u128)
        .ok_or(LaunchpadError::MathOverflow)?;
    let new_virtual_sol = ceil_div(k, new_virtual_tokens)?;
    let output = (virtual_sol as u128)
        .checked_sub(new_virtual_sol)
        .ok_or(LaunchpadError::MathOverflow)?;
    u64::try_from(output).map_err(|_| error!(LaunchpadError::MathOverflow))
}

fn ceil_div(numerator: u128, denominator: u128) -> Result<u128> {
    require!(denominator > 0, LaunchpadError::MathOverflow);
    numerator
        .checked_add(denominator - 1)
        .ok_or(LaunchpadError::MathOverflow)?
        .checked_div(denominator)
        .ok_or_else(|| error!(LaunchpadError::MathOverflow))
}

fn transfer_program_lamports(from: &AccountInfo, to: &AccountInfo, amount: u64) -> Result<()> {
    require!(amount > 0, LaunchpadError::ZeroAmount);
    let from_balance = from.lamports();
    require!(from_balance >= amount, LaunchpadError::InsufficientCurveSol);
    **from.try_borrow_mut_lamports()? = from_balance
        .checked_sub(amount)
        .ok_or(LaunchpadError::MathOverflow)?;
    let to_balance = to.lamports();
    **to.try_borrow_mut_lamports()? = to_balance
        .checked_add(amount)
        .ok_or(LaunchpadError::MathOverflow)?;
    Ok(())
}

