import "dotenv/config";
import { Keypair, PublicKey } from "@solana/web3.js";
import bs58 from "bs58";

function required(name: string): string {
  const value = process.env[name];
  if (!value) throw new Error(`Missing required environment variable ${name}`);
  return value;
}

function parseSecret(raw: string): Uint8Array {
  const trimmed = raw.trim();
  if (trimmed.startsWith("[")) return Uint8Array.from(JSON.parse(trimmed));
  return bs58.decode(trimmed);
}

export const config = {
  rpcUrl: required("RPC_URL"),
  programId: new PublicKey(required("PROGRAM_ID")),
  coreMint: new PublicKey(process.env.CORE_MINT ?? "4FdojUmXeaFMBG6yUaoufAC5Bz7u9AwnSAMizkx5pump"),
  authority: Keypair.fromSecretKey(parseSecret(required("MIGRATION_AUTHORITY_SECRET"))),
  jupiterApiKey: required("JUPITER_API_KEY"),
  solReserveLamports: BigInt(process.env.MIGRATOR_SOL_RESERVE_LAMPORTS ?? "2000000000"),
  slippageBps: Number(process.env.JUPITER_SLIPPAGE_BPS ?? "300"),
  raydiumFeeConfigIndex: Number(process.env.RAYDIUM_FEE_CONFIG_INDEX ?? "0"),
  pollIntervalMs: Number(process.env.POLL_INTERVAL_MS ?? "15000"),
  stateFile: process.env.MIGRATION_STATE_FILE ?? "./data/migrations.json",
};
